// src/pages/ForecastPage.jsx
import React, { useEffect, useState } from "react";
import forecastApi from "../api/forecastApi";
import NumberInput from "../components/NumberInput";

function ForecastPage() {
  const [period, setPeriod] = useState("2026-W03");
  const [rows, setRows] = useState([]);
  const [message, setMessage] = useState("");

  // form fields for one line
  const [productId, setProductId] = useState(1);
  const [gradePackId, setGradePackId] = useState(1);
  const [forecastQty, setForecastQty] = useState(0);

  useEffect(() => {
    loadForecast(period);
  }, [period]);

  const loadForecast = async (p) => {
    const data = await forecastApi.getByPeriod(p);
    setRows(data);
  };

  const handleAddLine = async () => {
    if (!forecastQty || forecastQty <= 0) return;

    // create a new array with existing lines + new one
    const newRows = [
      ...rows,
      { product_id: productId, grade_pack_id: gradePackId, forecast_qty: forecastQty }
    ];

    await forecastApi.save(period, newRows);
    setMessage("Forecast line added");
    setProductId(1);
    setGradePackId(1);
    setForecastQty(0);

    await loadForecast(period);
  };

  return (
    <div>
      <h2>Demand Forecast</h2>

      <div style={{ marginBottom: 8 }}>
        <label>
          Period:
          <input
            value={period}
            onChange={(e) => setPeriod(e.target.value)}
            style={{ marginLeft: 6 }}
          />
        </label>
      </div>

      {/* Create Forecast Line form */}
      <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
        <NumberInput value={productId} onChange={setProductId} min={1} />
        <NumberInput value={gradePackId} onChange={setGradePackId} min={1} />
        <NumberInput value={forecastQty} onChange={setForecastQty} min={0} />
        <button onClick={handleAddLine}>Create Forecast Line</button>
      </div>

      {/* Read-only table of all lines */}
      <table className="pp-table">
        <thead>
          <tr>
            
            <th>Product</th>
            <th>Grade/Pack</th>
            <th>Forecast Qty</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, index) => (
            <tr key={r.id || index}>
              
              <td>{r.product_id}</td>
              <td>{r.grade_pack_id}</td>
              <td>{r.forecast_qty}</td>
            </tr>
          ))}
          {rows.length === 0 && (
            <tr>
              <td colSpan={4}>No forecast lines for this period</td>
            </tr>
          )}
        </tbody>
      </table>

      {message && <p>{message}</p>}
    </div>
  );
}

export default ForecastPage;
